mapper.select:
select count(*) from mar_submit
    left join mar_goods
        on mar_goods.id=mar_submit.goods_id
where mar_submit.goods_id=#{goodsId}
  and mar_submit.user_id=#{userId}
  and mar_goods.goods_status=0;

mapper.delete:
delete mar_goods,mar_submit
from mar_goods
    inner join mar_submit
where mar_goods.id=mar_submit.goods_id
    and mar_submit.user_id=#{userId}
    and mar_submit.goods_id=#{goodsId}
